module top_module(clk, reset, mode, addr, data);input clk, reset, mode; 
 input [2:0] addr; 
 output [3:0] data; 
 (* mem2reg *) 
 reg [3:0] mem [0:7]; 
 assign data = mem[addr]; 
 integer i; 
   wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin 
  if (reset) begin 
  for (i=0; i<8; i=i+1) 
  mem[i] <= i; 
  end else 
  if (mode) begin 
  for (i=0; i<8; i=i+1) 
  mem[i] <= mem[i]+1; 
  end else begin 
  mem[addr] <= 0; 
  end 
 end 
 endmodule
